import React, { useState, useCallback, useRef, useEffect } from 'react';
import { DuaCategory, Dua } from '../types';
import DuaCard from './DuaCard';
import { 
    PlayIcon, 
    SunIcon, 
    CloudIcon, 
    ShieldCheckIcon, 
    SparklesIcon, 
    BriefcaseIcon, 
    GlobeAltIcon, 
    LeafIcon, 
    GiftIcon, 
    HeartIcon, 
    MoonIcon, 
    CategoryIcon 
} from './Icons';

const DuaCategories: React.FC = () => {
  const [categories, setCategories] = useState<DuaCategory[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [selectedCategory, setSelectedCategory] = useState<DuaCategory | null>(null);
  const audioPlayerRef = useRef<HTMLAudioElement | null>(null);
  const playlistRef = useRef<Dua[]>([]);
  const currentTrackIndexRef = useRef(0);

  useEffect(() => {
    fetch('/data/duas.json')
        .then(res => res.json())
        .then(data => {
            setCategories(data.categories);
            setIsLoading(false);
        })
        .catch(err => {
            console.error("Failed to load categories:", err);
            setIsLoading(false);
        });
  }, []);

  const getCategoryIcon = (name: string) => {
      const lowerName = name.toLowerCase();
      if (lowerName.includes("morning")) return SunIcon;
      if (lowerName.includes("forgiveness")) return CloudIcon;
      if (lowerName.includes("protection")) return ShieldCheckIcon;
      if (lowerName.includes("gratitude")) return GiftIcon;
      if (lowerName.includes("zikr")) return SparklesIcon;
      if (lowerName.includes("stress")) return HeartIcon;
      if (lowerName.includes("health")) return LeafIcon;
      if (lowerName.includes("rizq")) return BriefcaseIcon;
      if (lowerName.includes("travel")) return GlobeAltIcon;
      if (lowerName.includes("death")) return MoonIcon;
      if (lowerName.includes("sleep")) return MoonIcon;
      return CategoryIcon;
  };

  const handlePlayAll = useCallback(() => {
    const validPlaylist = selectedCategory?.duas.filter(d => d.audio) || [];
    if (!validPlaylist.length) return;

    playlistRef.current = validPlaylist;
    currentTrackIndexRef.current = 0;

    if (!audioPlayerRef.current) {
        audioPlayerRef.current = document.getElementById('global-audio-player') as HTMLAudioElement;
    }

    const audioPlayer = audioPlayerRef.current;
    if (!audioPlayer) return;

    audioPlayer.pause();
    audioPlayer.currentTime = 0;

    const playNextTrack = () => {
        if (currentTrackIndexRef.current >= playlistRef.current.length) {
            audioPlayer.onended = null; // Playlist finished
            return;
        }
        const track = playlistRef.current[currentTrackIndexRef.current];
        audioPlayer.src = track.audio;
        const playPromise = audioPlayer.play();
        if(playPromise !== undefined) {
            playPromise.catch(e => {
                console.error("Playlist audio error:", e);
                currentTrackIndexRef.current++;
                playNextTrack(); // Skip to next track on error
            });
        }
        currentTrackIndexRef.current++;
    };

    audioPlayer.onended = playNextTrack;
    playNextTrack();
  }, [selectedCategory]);


  if (selectedCategory) {
    const hasAudio = selectedCategory.duas.some(d => d.audio);
    return (
      <div className="space-y-6">
        <div className="flex justify-between items-center">
            <button onClick={() => setSelectedCategory(null)} className="text-yellow-400 flex items-center gap-1 hover:text-yellow-300 transition-colors">
                <span className="text-xl">&larr;</span> Back
            </button>
            <h1 className="text-lg font-bold text-center text-white truncate max-w-[200px]">{selectedCategory.name}</h1>
            <div className="w-12"></div>
        </div>

        <button
            onClick={handlePlayAll}
            disabled={!hasAudio}
            className="w-full flex items-center justify-center gap-2 bg-gradient-to-r from-yellow-500/20 to-yellow-400/20 text-yellow-300 px-6 py-4 rounded-2xl hover:from-yellow-500/30 hover:to-yellow-400/30 transition-all border border-yellow-400/20 disabled:opacity-50 disabled:cursor-not-allowed shadow-lg shadow-yellow-900/10"
        >
            <PlayIcon className="w-6 h-6"/>
            <span className="font-semibold">{hasAudio ? 'Play All Audio' : 'Audio unavailable'}</span>
        </button>

        <div className="space-y-4">
          {selectedCategory.duas.map(dua => (
            <DuaCard key={dua.id} dua={dua} />
          ))}
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-8">
      <div className="flex flex-col space-y-2">
        <h1 className="text-3xl font-bold text-white tracking-tight">Browse Categories</h1>
        <p className="text-gray-400 text-sm">Find the perfect Dua for every moment of your life.</p>
      </div>

      {isLoading ? (
        <div className="flex flex-col items-center justify-center py-20 space-y-4">
          <div className="w-12 h-12 border-4 border-yellow-400/20 border-t-yellow-400 rounded-full animate-spin"></div>
          <p className="text-gray-500 font-medium">Preparing library...</p>
        </div>
      ) : (
        <div className="grid grid-cols-3 gap-x-4 gap-y-8">
          {categories.map((category) => {
            const Icon = getCategoryIcon(category.name);
            return (
                <button
                  key={category.name}
                  onClick={() => setSelectedCategory(category)}
                  className="flex flex-col items-center group focus:outline-none"
                >
                  {/* 3D Golden Icon Container */}
                  <div className="relative mb-3">
                    {/* Shadow underneath */}
                    <div className="absolute -bottom-1 left-1/2 -translate-x-1/2 w-8 h-2 bg-black/40 blur-md rounded-full"></div>

                    {/* The "Golden Sphere" */}
                    <div className="relative w-16 h-16 rounded-3xl flex items-center justify-center transition-all duration-300 transform group-hover:-translate-y-1.5 group-hover:scale-105 active:scale-95 shadow-xl
                      bg-gradient-to-br from-[#FDB931] via-[#FFF3A1] to-[#9E7E1D]
                      before:absolute before:inset-[1px] before:rounded-3xl before:bg-gradient-to-tl before:from-transparent before:to-white/40
                      after:absolute after:inset-0 after:rounded-3xl after:shadow-[inset_0_2px_4px_rgba(255,255,255,0.5),inset_0_-2px_4px_rgba(0,0,0,0.3)]
                    ">
                      {/* Inner darker gold for contrast */}
                      <div className="relative z-10 text-amber-900 drop-shadow-[0_1px_1px_rgba(255,255,255,0.5)]">
                        <Icon className="w-7 h-7 stroke-[2.5]" />
                      </div>
                    </div>
                  </div>

                  <h2 className="text-[11px] font-bold text-gray-400 group-hover:text-yellow-400 transition-colors text-center uppercase tracking-wider leading-tight">
                    {category.name.replace(/^[^\w]+/, '').trim()}
                  </h2>
                </button>
            );
          })}
        </div>
      )}

      {/* Footer message */}
      <div className="py-10 text-center opacity-40">
        <p className="text-xs text-gray-500 italic">"Call upon Me; I will respond to you."</p>
      </div>
    </div>
  );
};

export default DuaCategories;

import React from 'react';
import { AppView } from '../types';
import { HomeIcon, ZikrIcon, JournalIcon, AmeenIcon, CategoryIcon } from './Icons';

interface BottomNavProps {
  activeView: AppView;
  setActiveView: (view: AppView) => void;
}

const NavItem: React.FC<{
  icon: React.ElementType;
  label: AppView;
  isActive: boolean;
  onClick: () => void;
}> = ({ icon: Icon, label, isActive, onClick }) => (
  <button
    onClick={onClick}
    className="relative flex flex-col items-center justify-center flex-1 h-full transition-all duration-500 group"
  >
    {/* Active Glow Effect */}
    <div className={`absolute inset-0 flex items-center justify-center transition-opacity duration-500 ${isActive ? 'opacity-100' : 'opacity-0'}`}>
        <div className="w-12 h-12 bg-yellow-400/10 blur-xl rounded-full"></div>
    </div>

    {/* Icon Wrapper */}
    <div className={`relative z-10 transition-all duration-300 ${isActive ? '-translate-y-1.5' : 'group-hover:-translate-y-1'}`}>
      <Icon className={`w-6 h-6 transition-colors duration-300 ${isActive ? 'text-yellow-400' : 'text-gray-400 group-hover:text-gray-200'}`} />
    </div>

    {/* Label */}
    <span className={`relative z-10 text-[10px] font-bold uppercase tracking-widest transition-all duration-300 ${isActive ? 'text-yellow-400 opacity-100 translate-y-0.5' : 'text-gray-500 opacity-0 translate-y-2 group-hover:opacity-60 group-hover:translate-y-1'}`}>
      {label}
    </span>

    {/* Active Dot */}
    {isActive && (
      <div className="absolute bottom-1 w-1 h-1 bg-yellow-400 rounded-full shadow-[0_0_8px_rgba(250,204,21,0.8)] animate-pulse"></div>
    )}
  </button>
);

const BottomNav: React.FC<BottomNavProps> = ({ activeView, setActiveView }) => {
  const navItems = [
    { icon: HomeIcon, label: AppView.Home },
    { icon: ZikrIcon, label: AppView.Zikr },
    { icon: JournalIcon, label: AppView.Journal },
    { icon: AmeenIcon, label: AppView.Ameen },
    { icon: CategoryIcon, label: AppView.Categories },
  ];

  return (
    <div className="fixed bottom-6 left-1/2 -translate-x-1/2 w-[92%] max-w-lg z-40">
      <nav className="h-16 bg-gray-900/80 backdrop-blur-2xl border border-white/10 shadow-[0_8px_32px_rgba(0,0,0,0.5)] rounded-[2rem] px-4 overflow-hidden">
        <div className="flex justify-between items-center h-full relative">
          {navItems.map((item) => (
            <NavItem
              key={item.label}
              icon={item.icon}
              label={item.label}
              isActive={activeView === item.label}
              onClick={() => setActiveView(item.label)}
            />
          ))}
        </div>
      </nav>
    </div>
  );
};

export default BottomNav;
